import { Component } from '@angular/core';
import { Router } from '@angular/router';

import { FarmerService } from 'src/app/core/services/farmer.service';

@Component({
  selector: 'app-add-farmer',
  templateUrl: './add-farmer.component.html'
})
export class AddFarmerComponent {

  farmer = {
    name: '',
    mobile: '',
    village: '',
    state: '',
    landArea: 0
  };

  constructor(
    private farmerService: FarmerService,
    private router: Router
  ) {
  }

  saveFarmer() {

    this.farmerService
      .addFarmer(this.farmer)
      .subscribe((response: any) => {

        if (response.success) {

          alert('Farmer Added');

          this.router.navigate(['/farmers']);
        }
      });
  }
}
<app-navbar></app-navbar>

<div class="container mt-4">

  <div class="card p-4">

    <h3 class="mb-4">
      Add Farmer
    </h3>

    <div class="row">

      <div class="col-md-6 mb-3">

        <label>Name</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.name">

      </div>

      <div class="col-md-6 mb-3">

        <label>Mobile</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.mobile">

      </div>

      <div class="col-md-6 mb-3">

        <label>Village</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.village">

      </div>

      <div class="col-md-6 mb-3">

        <label>State</label>

        <input type="text"
               class="form-control"
               [(ngModel)]="farmer.state">

      </div>

      <div class="col-md-6 mb-3">

        <label>Land Area</label>

        <input type="number"
               class="form-control"
               [(ngModel)]="farmer.landArea">

      </div>

    </div>

    <button class="btn btn-success"
            (click)="saveFarmer()">

      Save Farmer
    </button>

  </div>

</div>
